################################################################################
# 02_sex_specific_lasso_protein_selection.R
#
# Sex-specific inflammatory and proteomic biomarkers associated with
# 10-year all-cause mortality risk
#
# Manuscript section:
#   Sex-specific inflammatory and proteomic biomarkers associated with
#   10-year all-cause mortality risk
#
# Purpose:
#   1. Read the organized UK Biobank derivation set generated by
#      01_data_extraction_baseline_characteristics.R.
#   2. Standardize Olink NPX protein values to z-scores using the UK Biobank
#      derivation set.
#   3. Perform sex-specific LASSO-regularized Cox regression in the UK Biobank
#      derivation set, with conventional mortality risk factors included as
#      unpenalized covariates.
#   4. Assess selection stability using 1,000 bootstrap resamples.
#   5. Retain proteins selected in at least 95% of bootstrap samples.
#
# Main outputs:
#   results/analysis_datasets/
#     ukb_derivation_standardized_target_inflammation.rds
#     ukb_derivation_standardized_explore.rds
#     protein_standardization_parameters_target_inflammation.csv
#     protein_standardization_parameters_explore.csv
#
#   results/selected_proteins/
#     selected_proteins_target_inflammation_men.csv
#     selected_proteins_target_inflammation_women.csv
#     selected_proteins_explore_men.csv
#     selected_proteins_explore_women.csv
#     selected_proteins_summary.csv
#
#   results/models/
#     lasso_cv_target_inflammation_men.rds
#     lasso_cv_target_inflammation_women.rds
#     lasso_cv_explore_men.rds
#     lasso_cv_explore_women.rds
#     bootstrap_selection_target_inflammation_men.rds
#     bootstrap_selection_target_inflammation_women.rds
#     bootstrap_selection_explore_men.rds
#     bootstrap_selection_explore_women.rds
#
# Notes:
#   - This script assumes that covariates and proteins have already been imputed,
#     consistent with the manuscript.
#   - Proteins are standardized to mean = 0 and SD = 1 in the UKB derivation set.
#   - In sex-stratified models, sex is not included as a covariate.
#   - Conventional risk factors are forced into the model by assigning
#     penalty.factor = 0 in glmnet.
################################################################################


# ==============================================================================
# 0. Packages
# ==============================================================================

required_packages <- c(
  "dplyr", "tidyr", "purrr", "stringr", "readr", "tibble",
  "survival", "glmnet", "Matrix", "doParallel", "foreach"
)

install_if_missing <- function(pkgs) {
  missing_pkgs <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(missing_pkgs) > 0) install.packages(missing_pkgs)
  invisible(lapply(pkgs, library, character.only = TRUE))
}

install_if_missing(required_packages)


# ==============================================================================
# 1. User configuration
# ==============================================================================

set.seed(20240618)

# ---- Input from Part 1 ----
file_ukb_derivation <- "results/analysis_datasets/ukb_derivation.rds"

# ---- Protein list files ----
# One protein name per line. Names must match column names in ukb_derivation.rds.
file_target_inflammation_proteins <- "data/target_inflammation_proteins.txt"
file_explore_proteins             <- "data/explore_proteins.txt"

# ---- Output directories ----
dir_results  <- "results"
dir_dataout  <- file.path(dir_results, "analysis_datasets")
dir_selected <- file.path(dir_results, "selected_proteins")
dir_models   <- file.path(dir_results, "models")
dir_logs     <- file.path(dir_results, "logs")

dir.create(dir_dataout,  recursive = TRUE, showWarnings = FALSE)
dir.create(dir_selected, recursive = TRUE, showWarnings = FALSE)
dir.create(dir_models,   recursive = TRUE, showWarnings = FALSE)
dir.create(dir_logs,     recursive = TRUE, showWarnings = FALSE)

# ---- Core variables ----
sex_var   <- "sex_share"
time_var  <- "followup_time"
event_var <- "death_10y"

# Sex labels used in the dataset. Edit if your dataset uses different labels.
male_labels   <- c("Male", "Men", "M", "1", 1)
female_labels <- c("Female", "Women", "F", "0", 0, "2", 2)

# Conventional risk factors used in the LASSO-Cox models.
# Sex is removed automatically in sex-stratified analyses.
conventional_risk_factors <- c(
  "age_share",
  "sex_share",
  "education_share",
  "smoking_share",
  "activity_share",
  "alcohol_share",
  "BMI_share",
  "hypertension_share",
  "diabetes_share",
  "dyslipidemia_share",
  "CVD_share",
  "cancer_share"
)

# Continuous covariates. Age is modeled per 10-year increment.
continuous_covariates <- c("age_share")

# glmnet parameters
n_folds <- 10
lambda_choice <- "lambda.min"      # use "lambda.1se" for a more parsimonious model
n_bootstrap <- 1000
selection_frequency_threshold <- 0.95

# Parallel settings
use_parallel <- TRUE
n_cores <- max(1, parallel::detectCores() - 1)


# ==============================================================================
# 2. Helper functions
# ==============================================================================

read_protein_list <- function(path, panel_name) {
  if (!file.exists(path)) {
    stop("Protein list file not found for ", panel_name, ": ", path)
  }

  proteins <- readr::read_lines(path)
  proteins <- proteins[proteins != ""]
  proteins <- unique(trimws(proteins))

  if (length(proteins) == 0) {
    stop("No proteins found in: ", path)
  }

  proteins
}

standardize_proteins <- function(data, protein_vars, panel_name) {
  available_proteins <- intersect(protein_vars, names(data))
  missing_proteins <- setdiff(protein_vars, names(data))

  if (length(missing_proteins) > 0) {
    warning(
      panel_name, ": ", length(missing_proteins),
      " proteins were not found in the derivation dataset and will be ignored."
    )
    readr::write_lines(
      missing_proteins,
      file.path(dir_logs, paste0("missing_proteins_", panel_name, ".txt"))
    )
  }

  if (length(available_proteins) == 0) {
    stop("No available proteins for panel: ", panel_name)
  }

  center <- vapply(data[available_proteins], function(x) mean(as.numeric(x), na.rm = TRUE), numeric(1))
  scale  <- vapply(data[available_proteins], function(x) stats::sd(as.numeric(x), na.rm = TRUE), numeric(1))

  scale[is.na(scale) | scale == 0] <- 1

  standardized <- data
  standardized[available_proteins] <- purrr::map2(
    standardized[available_proteins],
    available_proteins,
    ~ (as.numeric(.x) - center[.y]) / scale[.y]
  )

  scaling_parameters <- tibble::tibble(
    panel = panel_name,
    protein = available_proteins,
    center = as.numeric(center[available_proteins]),
    scale = as.numeric(scale[available_proteins])
  )

  readr::write_csv(
    scaling_parameters,
    file.path(dir_dataout, paste0("protein_standardization_parameters_", panel_name, ".csv"))
  )

  list(
    data = standardized,
    proteins = available_proteins,
    scaling_parameters = scaling_parameters
  )
}

standardize_sex <- function(x) {
  x_chr <- as.character(x)
  dplyr::case_when(
    x_chr %in% as.character(male_labels) ~ "Men",
    x_chr %in% as.character(female_labels) ~ "Women",
    TRUE ~ x_chr
  )
}

prepare_model_data <- function(data, protein_vars, sex_level) {
  dat <- data %>%
    dplyr::mutate(sex_standardized = standardize_sex(.data[[sex_var]])) %>%
    dplyr::filter(sex_standardized == sex_level)

  covariates <- setdiff(conventional_risk_factors, sex_var)
  covariates <- intersect(covariates, names(dat))

  required_vars <- c(time_var, event_var, covariates, protein_vars)
  missing_vars <- setdiff(required_vars, names(dat))
  if (length(missing_vars) > 0) {
    stop("Missing variables for ", sex_level, ": ", paste(missing_vars, collapse = ", "))
  }

  analysis_dat <- dat[, required_vars, drop = FALSE]

  analysis_dat[[time_var]] <- as.numeric(analysis_dat[[time_var]])
  analysis_dat[[event_var]] <- as.integer(as.numeric(as.character(analysis_dat[[event_var]])) == 1)

  for (v in covariates) {
    if (v %in% continuous_covariates) {
      analysis_dat[[v]] <- as.numeric(analysis_dat[[v]])
      if (v == "age_share") {
        analysis_dat[[v]] <- analysis_dat[[v]] / 10
      }
    } else {
      analysis_dat[[v]] <- as.factor(analysis_dat[[v]])
    }
  }

  # Reference levels used in the original analysis scripts.
  if ("BMI_share" %in% names(analysis_dat)) {
    analysis_dat$BMI_share <- as.factor(analysis_dat$BMI_share)
    if (nlevels(analysis_dat$BMI_share) >= 2) {
      analysis_dat$BMI_share <- stats::relevel(
        analysis_dat$BMI_share,
        ref = levels(analysis_dat$BMI_share)[2]
      )
    }
  }

  if ("alcohol_share" %in% names(analysis_dat)) {
    analysis_dat$alcohol_share <- as.factor(analysis_dat$alcohol_share)
    if (nlevels(analysis_dat$alcohol_share) >= 2) {
      analysis_dat$alcohol_share <- stats::relevel(
        analysis_dat$alcohol_share,
        ref = tail(levels(analysis_dat$alcohol_share), 1)
      )
    }
  }

  for (p in protein_vars) {
    analysis_dat[[p]] <- as.numeric(analysis_dat[[p]])
  }

  analysis_dat <- analysis_dat %>%
    dplyr::filter(!is.na(.data[[time_var]]), .data[[time_var]] > 0) %>%
    tidyr::drop_na() %>%
    droplevels()

  if (nrow(analysis_dat) == 0) stop("No complete observations for ", sex_level)
  if (sum(analysis_dat[[event_var]] == 1) == 0) stop("No events for ", sex_level)

  # Remove covariates with no variation after sex stratification and complete-case filtering.
  covariates_final <- covariates[purrr::map_lgl(covariates, function(v) {
    if (is.factor(analysis_dat[[v]])) {
      nlevels(analysis_dat[[v]]) >= 2
    } else {
      stats::sd(analysis_dat[[v]], na.rm = TRUE) > 0
    }
  })]

  list(
    data = analysis_dat,
    covariates = covariates_final,
    proteins = protein_vars
  )
}

make_glmnet_matrix <- function(data, covariates, proteins) {
  predictors <- c(covariates, proteins)

  mm <- stats::model.matrix(
    stats::as.formula(paste("~", paste(predictors, collapse = " + "))),
    data = data
  )

  x <- mm[, colnames(mm) != "(Intercept)", drop = FALSE]
  y <- survival::Surv(data[[time_var]], data[[event_var]])

  # glmnet expands categorical covariates into multiple dummy variables.
  # Protein columns keep their original names because they are numeric.
  protein_columns <- colnames(x) %in% proteins

  penalty_factor <- ifelse(protein_columns, 1, 0)

  list(
    x = x,
    y = y,
    penalty_factor = penalty_factor,
    protein_columns = protein_columns,
    predictors = predictors
  )
}

extract_selected_proteins <- function(cvfit, protein_vars, lambda = lambda_choice) {
  beta <- as.matrix(stats::coef(cvfit, s = lambda))
  selected_terms <- rownames(beta)[as.numeric(beta[, 1]) != 0]
  intersect(selected_terms, protein_vars)
}

fit_lasso_cox <- function(model_data, alpha = 1) {
  mm <- make_glmnet_matrix(
    data = model_data$data,
    covariates = model_data$covariates,
    proteins = model_data$proteins
  )

  cvfit <- glmnet::cv.glmnet(
    x = mm$x,
    y = mm$y,
    family = "cox",
    alpha = alpha,
    nfolds = n_folds,
    penalty.factor = mm$penalty_factor,
    standardize = FALSE,
    type.measure = "deviance",
    parallel = use_parallel
  )

  selected <- extract_selected_proteins(cvfit, model_data$proteins, lambda = lambda_choice)

  list(
    cvfit = cvfit,
    selected = selected,
    model_matrix_columns = colnames(mm$x),
    penalty_factor = mm$penalty_factor
  )
}

bootstrap_lasso_selection <- function(model_data, panel_name, sex_level) {
  dat <- model_data$data
  proteins <- model_data$proteins

  protein_selection_counts <- setNames(rep(0L, length(proteins)), proteins)

  for (b in seq_len(n_bootstrap)) {
    boot_index <- sample(seq_len(nrow(dat)), size = nrow(dat), replace = TRUE)
    boot_data <- dat[boot_index, , drop = FALSE] %>% droplevels()

    boot_model_data <- list(
      data = boot_data,
      covariates = model_data$covariates,
      proteins = model_data$proteins
    )

    fit_b <- tryCatch(
      fit_lasso_cox(boot_model_data),
      error = function(e) {
        message("Bootstrap error in ", panel_name, " / ", sex_level, " / iteration ", b, ": ", e$message)
        NULL
      }
    )

    if (!is.null(fit_b)) {
      protein_selection_counts[fit_b$selected] <- protein_selection_counts[fit_b$selected] + 1L
    }

    if (b %% 50 == 0) {
      message(panel_name, " / ", sex_level, ": bootstrap ", b, " of ", n_bootstrap)
    }
  }

  stability_table <- tibble::tibble(
    panel = panel_name,
    sex = sex_level,
    protein = names(protein_selection_counts),
    selection_count = as.integer(protein_selection_counts),
    selection_frequency = as.numeric(protein_selection_counts) / n_bootstrap,
    selected_stable = selection_frequency >= selection_frequency_threshold
  ) %>%
    dplyr::arrange(dplyr::desc(selection_frequency), protein)

  selected_stable <- stability_table %>%
    dplyr::filter(selected_stable) %>%
    dplyr::pull(protein)

  list(
    stability_table = stability_table,
    selected_stable = selected_stable
  )
}

run_panel_selection <- function(data, protein_vars, panel_name) {
  message("\n==============================")
  message("Panel: ", panel_name)
  message("==============================")

  standardized <- standardize_proteins(data, protein_vars, panel_name)

  readr::write_rds(
    standardized$data,
    file.path(dir_dataout, paste0("ukb_derivation_standardized_", panel_name, ".rds"))
  )

  panel_results <- list()

  for (sex_level in c("Men", "Women")) {
    message("\nRunning sex-specific LASSO-Cox selection: ", panel_name, " / ", sex_level)

    model_data <- prepare_model_data(
      data = standardized$data,
      protein_vars = standardized$proteins,
      sex_level = sex_level
    )

    cv_result <- fit_lasso_cox(model_data)

    cv_output_file <- file.path(dir_models, paste0("lasso_cv_", panel_name, "_", tolower(sex_level), ".rds"))
    readr::write_rds(cv_result, cv_output_file)

    initial_selection <- tibble::tibble(
      panel = panel_name,
      sex = sex_level,
      selection_stage = "cv_lasso",
      protein = cv_result$selected
    )

    bootstrap_result <- bootstrap_lasso_selection(model_data, panel_name, sex_level)

    bootstrap_output_file <- file.path(
      dir_models,
      paste0("bootstrap_selection_", panel_name, "_", tolower(sex_level), ".rds")
    )
    readr::write_rds(bootstrap_result, bootstrap_output_file)

    stable_selection <- bootstrap_result$stability_table %>%
      dplyr::filter(selected_stable) %>%
      dplyr::mutate(selection_stage = "bootstrap_stable") %>%
      dplyr::select(panel, sex, selection_stage, protein, selection_count, selection_frequency)

    output_csv <- file.path(
      dir_selected,
      paste0("selected_proteins_", panel_name, "_", tolower(sex_level), ".csv")
    )

    readr::write_csv(stable_selection, output_csv)

    readr::write_csv(
      bootstrap_result$stability_table,
      file.path(dir_selected, paste0("selection_stability_", panel_name, "_", tolower(sex_level), ".csv"))
    )

    panel_results[[sex_level]] <- list(
      model_data_summary = tibble::tibble(
        panel = panel_name,
        sex = sex_level,
        n = nrow(model_data$data),
        events = sum(model_data$data[[event_var]] == 1),
        n_proteins_available = length(model_data$proteins),
        n_cv_selected = length(cv_result$selected),
        n_bootstrap_stable_selected = length(bootstrap_result$selected_stable)
      ),
      cv_selected = initial_selection,
      stable_selected = stable_selection,
      stability_table = bootstrap_result$stability_table,
      cv_model_file = cv_output_file,
      bootstrap_file = bootstrap_output_file
    )
  }

  panel_results
}


