apply_protein_standardization <- function(data, scaling_file){
  scaling <- readr::read_csv(scaling_file, show_col_types = FALSE)
  proteins <- intersect(scaling$protein, names(data))
  out <- data
  for(p in proteins){
    center_p <- scaling$center[match(p, scaling$protein)]
    scale_p <- scaling$scale[match(p, scaling$protein)]
    if(is.na(scale_p) || scale_p == 0) scale_p <- 1
    out[[p]] <- (as.numeric(out[[p]]) - center_p) / scale_p
  }
  out
}

prepare_forest_data <- function(data, protein, sex_level){
  dat <- data %>%
    mutate(sex_standardized = standardize_sex(.data[[sex_var]])) %>%
    filter(sex_standardized == sex_level)
  
  covariates <- setdiff(conventional_risk_factors, sex_var)
  covariates <- intersect(covariates, names(dat))
  required_vars <- c(time_var, event_var, protein, covariates)
  
  dat <- dat[, required_vars, drop = FALSE]
  dat[[time_var]] <- as.numeric(dat[[time_var]])
  dat[[event_var]] <- as.integer(as.numeric(as.character(dat[[event_var]])) == 1)
  dat[[protein]] <- as.numeric(dat[[protein]])
  
  for(v in covariates){
    if(v %in% continuous_covariates){
      dat[[v]] <- as.numeric(dat[[v]])
      if(v == "age_share") dat[[v]] <- dat[[v]] / 10
    } else {
      dat[[v]] <- as.factor(dat[[v]])
    }
  }
  
  dat <- dat %>%
    filter(!is.na(.data[[time_var]]), .data[[time_var]] > 0) %>%
    tidyr::drop_na() %>%
    droplevels()
  
  covariates_final <- covariates[purrr::map_lgl(covariates, function(v){
    if(is.factor(dat[[v]])) nlevels(dat[[v]]) >= 2 else stats::sd(dat[[v]], na.rm = TRUE) > 0
  })]
  
  list(data = dat, covariates = covariates_final)
}

run_protein_cox <- function(data, protein, sex_level, dataset_name, panel_name){
  obj <- prepare_forest_data(data, protein, sex_level)
  dat <- obj$data
  covariates <- obj$covariates
  
  if(nrow(dat) == 0 || sum(dat[[event_var]] == 1, na.rm = TRUE) == 0){
    return(tibble(
      panel = panel_name,
      sex = sex_level,
      dataset = dataset_name,
      protein = protein,
      HR = NA_real_,
      CI_lower = NA_real_,
      CI_upper = NA_real_,
      P_value = NA_real_
    ))
  }
  
  fml <- as.formula(
    paste0(
      "survival::Surv(", time_var, ",", event_var, ") ~ ",
      paste(c(protein, covariates), collapse = " + ")
    )
  )
  
  fit <- survival::coxph(fml, data = dat)
  broom::tidy(fit, exponentiate = TRUE, conf.int = TRUE) %>%
    filter(term == protein) %>%
    transmute(
      panel = panel_name,
      sex = sex_level,
      dataset = dataset_name,
      protein = protein,
      HR = estimate,
      CI_lower = conf.low,
      CI_upper = conf.high,
      P_value = p.value
    )
}

make_forest_input <- function(panel_name, derivation_data, internal_data, external_data){
  selected_panel <- selected_proteins_all %>%
    filter(panel == panel_name) %>%
    select(panel, sex, protein) %>%
    distinct()
  
  purrr::pmap_dfr(selected_panel, function(panel, sex, selection_stage = NULL, protein, ...){
    bind_rows(
      run_protein_cox(derivation_data, protein, sex, "70% UKB", panel_name),
      run_protein_cox(internal_data, protein, sex, "30% UKB", panel_name),
      run_protein_cox(external_data, protein, sex, "ESTHER", panel_name)
    )
  }) %>%
    group_by(panel, sex, dataset) %>%
    mutate(FDR = p.adjust(P_value, method = "BH")) %>%
    ungroup()
}

plot_forest_by_sex <- function(dat, sex_label, xlab_text){
  df_sex <- dat %>%
    filter(sex == sex_label) %>%
    mutate(
      dataset = factor(dataset, levels = c("70% UKB", "30% UKB", "ESTHER")),
      dataset_label = dataset
    )
  
  protein_order <- df_sex %>%
    filter(dataset == "70% UKB") %>%
    arrange(desc(HR)) %>%
    pull(protein) %>%
    unique()
  
  df_sex <- df_sex %>%
    mutate(
      protein_f = factor(protein, levels = rev(protein_order)),
      base_y = as.numeric(protein_f) * 1.4,
      offset = case_when(
        dataset == "70% UKB" ~ 0.22,
        dataset == "30% UKB" ~ 0,
        dataset == "ESTHER" ~ -0.22
      ),
      y = base_y + offset
    )
  
  validated <- df_sex %>%
    filter(dataset %in% c("30% UKB", "ESTHER")) %>%
    group_by(protein) %>%
    summarise(validated = all(FDR < 0.05, na.rm = TRUE), .groups = "drop")
  
  tick_df <- df_sex %>%
    distinct(protein, protein_f) %>%
    left_join(validated, by = "protein") %>%
    mutate(
      y_tick = as.numeric(protein_f) * 1.4,
      protein_label = ifelse(validated, paste0(protein, "*"), protein)
    )
  
  ggplot(df_sex, aes(x = HR, y = y, color = dataset_label)) +
    geom_errorbarh(aes(xmin = CI_lower, xmax = CI_upper), height = 0, linewidth = 0.7) +
    geom_point(size = 2.2) +
    geom_vline(xintercept = 1, linetype = "dashed", color = "grey40") +
    scale_y_continuous(breaks = tick_df$y_tick, labels = tick_df$protein_label) +
    scale_x_log10(name = xlab_text) +
    scale_color_manual(values = c("70% UKB" = "#1A2930", "30% UKB" = "#A51C30", "ESTHER" = "#6A51A3")) +
    ggthemes::theme_few() +
    theme(
      legend.title = element_blank(),
      legend.position = "top",
      axis.title.y = element_blank(),
      axis.text.y = element_text(size = 11, color = "black", face = "italic"),
      axis.text.x = element_text(size = 11, color = "black"),
      panel.border = element_rect(colour = "black", fill = NA, linewidth = 1),
      plot.title = element_text(hjust = 0, size = 12, face = "bold")
    ) +
    ggtitle(sex_label)
}

export_forest_plots <- function(dat, panel_name, file_prefix){
  p_men <- plot_forest_by_sex(dat, "Men", "Adjusted HR per 1-SD increment")
  p_women <- plot_forest_by_sex(dat, "Women", "Adjusted HR per 1-SD increment")
  
  ggsave(file.path(dir_figures, paste0(file_prefix, "_men.pdf")), p_men, width = 4.5, height = 8)
  ggsave(file.path(dir_figures, paste0(file_prefix, "_women.pdf")), p_women, width = 4.5, height = 8)
  ggsave(file.path(dir_figures, paste0(file_prefix, "_men.png")), p_men, width = 4.5, height = 8, dpi = 600)
  ggsave(file.path(dir_figures, paste0(file_prefix, "_women.png")), p_women, width = 4.5, height = 8, dpi = 600)
  
  svglite::svglite(file.path(dir_figures, paste0(file_prefix, "_men.svg")), width = 4.5, height = 8)
  print(p_men)
  dev.off()
  
  svglite::svglite(file.path(dir_figures, paste0(file_prefix, "_women.svg")), width = 4.5, height = 8)
  print(p_women)
  dev.off()
  
  pptx_file <- file.path(dir_figures, paste0(file_prefix, "_editable.pptx"))
  doc <- officer::read_pptx()
  doc <- officer::add_slide(doc, layout = "Blank", master = "Office Theme")
  doc <- officer::ph_with(doc, rvg::dml(code = print(p_men)), location = officer::ph_location(width = 4.5, height = 8))
  doc <- officer::add_slide(doc, layout = "Blank", master = "Office Theme")
  doc <- officer::ph_with(doc, rvg::dml(code = print(p_women)), location = officer::ph_location(width = 4.5, height = 8))
  print(doc, target = pptx_file)
}

